        val timeSteps = (i + j).toLong() + 1 // steps taken so far (1-based)

        if (timeSteps % 2 == 1L) {
            // Odd step: move right or down
            if (j + 1 < cols) {
                val newJ = j + 1
                val moveCost = (i + 1).toLong() * (newJ + 1).toLong()
                val newCost = currentCost + moveCost
                if (newCost < dist[i][newJ]) {
                    dist[i][newJ] = newCost
                    heap.add(Triple(i, newJ, newCost))
                }
            }
            if (i + 1 < rows) {
                val newI = i + 1
                val moveCost = (newI + 1).toLong() * (j + 1).toLong()
                val newCost = currentCost + moveCost
                if (newCost < dist[newI][j]) {
                    dist[newI][j] = newCost
                    heap.add(Triple(newI, j, newCost))
                }
